package com.example.bankingapp;

import android.app.Activity;
import android.os.Bundle;
import android.widget.TextView;
import android.widget.Button;
import android.view.View;

public class MainActivity extends Activity {

    private double accountBalance = 1000.00; // Example balance

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        final TextView balanceTextView = findViewById(R.id.balanceTextView);
        Button depositButton = findViewById(R.id.depositButton);
        Button withdrawButton = findViewById(R.id.withdrawButton);

        balanceTextView.setText("Balance: $" + accountBalance);

        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransaction(200.00, "deposit", balanceTextView);
            }
        });

        withdrawButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransaction(100.00, "withdraw", balanceTextView);
            }
        });
    }

    private void processTransaction(double amount, String transactionType, TextView balanceTextView) {
        switch (transactionType) {
            case "deposit":
                accountBalance += amount;
                break;
            case "withdraw":
                if (accountBalance >= amount) {
                    accountBalance -= amount;
                } else {
                    // Handle insufficient funds; simple message for now
                    balanceTextView.setText("Insufficient funds. Current balance: $" + accountBalance);
                    return;
                }
                break;
        }
        balanceTextView.setText("Balance: $" + accountBalance);
    }
}